INSERT INTO sliders (title, description, image_url, button_text, button_url, card_link, status, order_index, created_at, updated_at) VALUES
('Program Mudik Gratis 2025', 'Daftar sekarang untuk program Mudik Gratis KORPRI BMKG. Kuota terbatas!', 'https://images.unsplash.com/photo-1544620347-c4fd4a3d5957?w=1200&h=400&fit=crop', 'Daftar Sekarang', '/mudikgratis', '/mudikgratis', 'published', 1, '2025-01-01 00:00:00', '2025-01-01 00:00:00'),
('Pelatihan Kompetensi ASN', 'Tingkatkan kompetensi profesional melalui pelatihan bersertifikat', 'https://images.unsplash.com/photo-1524178232363-1fb2b075b655?w=1200&h=400&fit=crop', 'Lihat Detail', '/kegiatan', '/kegiatan', 'published', 2, '2025-01-01 00:00:00', '2025-01-01 00:00:00'),
('Bakti Sosial KORPRI', 'Berbagi kebahagiaan dengan masyarakat melalui berbagai program sosial', 'https://images.unsplash.com/photo-1593113598332-cd288d649433?w=1200&h=400&fit=crop', 'Selengkapnya', '/kegiatan', '/kegiatan', 'published', 3, '2025-01-01 00:00:00', '2025-01-01 00:00:00'),
('Hari KORPRI 2025', 'Merayakan Hari KORPRI dengan berbagai kegiatan bernuansa kekeluargaan', 'https://images.unsplash.com/photo-1517486808906-6ca8b3f04846?w=1200&h=400&fit=crop', 'Lihat Acara', '/kegiatan', '/kegiatan', 'published', 4, '2025-01-01 00:00:00', '2025-01-01 00:00:00');
INSERT INTO kegiatan (title, description, category, date, location, images, status, created_at, updated_at) VALUES
('Pelatihan Kompetensi Digital ASN', 'Pelatihan intensif untuk meningkatkan kemampuan digital ASN dalam menghadapi era transformasi digital. Mencakup materi dasar-dasar komputer, penggunaan aplikasi perkantoran, dan pengelolaan data.', 'pelatihan', '2025-02-15', 'Aula BMKG Pusat', '["https://images.unsplash.com/photo-1524178232363-1fb2b075b655?w=600&h=400&fit=crop"]', 'published', '2025-01-01 00:00:00', '2025-01-01 00:00:00'),
('Hari KORPRI 2025 - Tema "Solidaritas Tumbuhkan Persatuan"', 'Peringatan Hari KORPRI ke-54 dengan berbagai kegiatan seperti upacara bendera, lomba kebersamaan, dan bakti sosial untuk mempererat tali silaturahmi antar anggota.', 'olahraga', '2025-01-29', 'Halaman Kantor BMKG Pusat', '["https://images.unsplash.com/photo-1517486808906-6ca8b3f04846?w=600&h=400&fit=crop"]', 'published', '2025-01-01 00:00:00', '2025-01-01 00:00:00'),
('Baksos Pemberian Sembako', 'Program bakti sosial berupa pembagian paket sembako kepada masyarakat sekitar kantor BMKG yang membutuhkan. Sebanyak 500 paket sembako akan dibagikan secara gratis.', 'baksos', '2025-02-20', 'Lingkungan Sekitar BMKG', '["https://images.unsplash.com/photo-1593113598332-cd288d649433?w=600&h=400&fit=crop"]', 'published', '2025-01-01 00:00:00', '2025-01-01 00:00:00'),
('Lomba Cerdas Cermat KORPRI', 'Kompetisi cerdas cermat antar unit kerja untuk menguji pengetahuan tentang ke-KORPRI-an, regulasi, dan program kerja BMKG. Lomba ini bertujuan meningkatkan wawasan dan soliditas antar anggota.', 'perlombaan', '2025-03-10', 'Aula BMKG Pusat', '["https://images.unsplash.com/photo-1517486808906-6ca8b3f04846?w=600&h=400&fit=crop"]', 'published', '2025-01-01 00:00:00', '2025-01-01 00:00:00'),
('Senam Sehat Bersama', 'Kegiatan senam sehat rutin setiap hari Jumat pagi untuk menjaga kesehatan dan kebugaran fisik seluruh anggota KORPRI BMKG. Terbuka untuk seluruh pegawai dan keluarga.', 'olahraga', '2025-01-10', 'Lapangan BMKG', '["https://images.unsplash.com/photo-1571019614242-c5c5dee9f50b?w=600&h=400&fit=crop"]', 'published', '2025-01-01 00:00:00', '2025-01-01 00:00:00');
INSERT INTO program (title, description, category, registration_link, status, created_at, updated_at) VALUES
('Program Mudik Gratis 2025', 'Program Mudik Gratis KORPRI BMKG untuk membantu anggota mudik Lebaran dengan menggunakan bus AKAP. Tersedia tujuan ke berbagai kota di Jawa dan Sumatera. Pendaftaran mulai 1 Februari 2025.', 'mudik', '/mudikgratis', 'published', '2025-01-01 00:00:00', '2025-01-01 00:00:00'),
('Program Kesejahteraan Pegawai', 'Program peningkatan kesejahteraan pegawai melalui berbagai fasilitas seperti bantuan kesehatan, beasiswa pendidikan anak, dan program pensiun dini. Tujuannya untuk meningkatkan kualitas hidup ASN.', 'kesejahteraan', NULL, 'published', '2025-01-01 00:00:00', '2025-01-01 00:00:00'),
('Pelatihan Kepemimpinan ASN', 'Program pelatihan kepemimpinan untuk ASN tingkat madya dan pratama. Mencakup materi manajemen SDM, komunikasi efektif, dan pengambilan keputusan strategis.', 'pelatihan', '/kegiatan', 'published', '2025-01-01 00:00:00', '2025-01-01 00:00:00'),
('Program Asuransi Kesehatan', 'Program asuransi kesehatan komprehensif untuk seluruh anggota KORPRI BMKG dan keluarga inti. Meliputi rawat inap, rawat jalan, dan pemeriksaan kesehatan berkala.', 'kesejahteraan', NULL, 'published', '2025-01-01 00:00:00', '2025-01-01 00:00:00'),
('Pelatihan Teknis Meteorologi', 'Program pelatihan teknis untuk meningkatkan kompetensi dalam bidang meteorologi, klimatologi, dan geofisika. Dibuka untuk seluruh staf teknis BMKG.', 'pelatihan', '/kegiatan', 'published', '2025-01-01 00:00:00', '2025-01-01 00:00:00');
INSERT INTO peraturan (title, description, category, file_url, status, created_at, updated_at) VALUES
('PP No. 94 Tahun 2021 tentang Disiplin PNS', 'Peraturan Pemerintah mengenai ketentuan disiplin Pegawai Negeri Sipil termasuk larangan, kewajiban, dan sanksi pelanggaran.', 'disiplin', 'https://www.bkn.go.id/pp-94-2021.pdf', 'published', '2025-01-01 00:00:00', '2025-01-01 00:00:00'),
('UU No. 5 Tahun 2014 tentang ASN', 'Undang-Undang dasar yang mengatur tentang Aparatur Sipil Negara mencakup prinsip dasar, kedudukan, dan fungsi ASN.', 'umum', 'https://www.bkn.go.id/uu-5-2014.pdf', 'published', '2025-01-01 00:00:00', '2025-01-01 00:00:00'),
('PP No. 11 Tahun 2017 tentang Manajemen PNS', 'Peraturan Pemerintah tentang manajemen Pegawai Negeri Sipil meliputi pengadaan, pengembangan karier, dan penilaian kinerja.', 'manajemen', 'https://www.bkn.go.id/pp-11-2017.pdf', 'published', '2025-01-01 00:00:00', '2025-01-01 00:00:00'),
('Peraturan KORPRI tentang Kode Etik', 'Peraturan organisasi KORPRI mengenai kode etik dan perilaku anggota dalam menjalankan tugas dan kehidupan sehari-hari.', 'etik', 'https://www.korpri.go.id/kode-etik.pdf', 'published', '2025-01-01 00:00:00', '2025-01-01 00:00:00'),
('PP No. 15 Tahun 2019 tentang Pengadaan PNS', 'Peraturan Pemerintah mengenai tata cara pengadaan Pegawai Negeri Sipil dari pelamar umum melalui seleksi CPNS dan PPPK.', 'rekrutmen', 'https://www.bkn.go.id/pp-15-2019.pdf', 'published', '2025-01-01 00:00:00', '2025-01-01 00:00:00');
